24	/**
25	 * Add a blockage entry to BOTH maps (blockedBy and blocks).
26	 * Creates entries with status "active".
27	 * Idempotent: if an identical active entry already exists, no duplicate is added.
28	 */
29	export function addBlockage(
30	  deps: DependenciesFile,
31	  blockedId: IssueId,
32	  blockerId: IssueId,
33	): DependenciesFile {
34	  const entry: BlockageEntry = { blockerId, blockedId, status: "active" };
35	
36	  // Check for duplicate active entry in blockedBy
37	  const existingBlockedBy = deps.blockedBy[blockedId] ?? [];
38	  const alreadyExists =
39	    existingBlockedBy.some(
40	      (e) => e.blockerId === blockerId && e.blockedId === blockedId && e.status === "active",
41	    ) &&
42	    (deps.blocks[blockerId] ?? []).some(
43	      (e) => e.blockerId === blockerId && e.blockedId === blockedId && e.status === "active",
44	    );
45	
46	  if (alreadyExists) {
47	    return deps;
48	  }
49	
50	  const newBlockedBy = {
51	    ...deps.blockedBy,
52	    [blockedId]: [...existingBlockedBy, entry],
53	  };
54	
55	  const existingBlocks = deps.blocks[blockerId] ?? [];
56	  const newBlocks = {
57	    ...deps.blocks,
58	    [blockerId]: [...existingBlocks, entry],
59	  };
60	
61	  return { blockedBy: newBlockedBy, blocks: newBlocks };
62	}
