64	/**
65	 * Mark a blockage as resolved in both maps.
66	 * Idempotent: if entry is already resolved or doesn't exist, no error.
67	 */
68	export function resolveBlockage(
69	  deps: DependenciesFile,
70	  blockedId: IssueId,
71	  blockerId: IssueId,
72	): DependenciesFile {
73	  // Resolve in blockedBy map
74	  const blockedByEntries = deps.blockedBy[blockedId];
75	  let newBlockedBy = { ...deps.blockedBy };
76	  if (blockedByEntries) {
77	    newBlockedBy = {
78	      ...deps.blockedBy,
79	      [blockedId]: blockedByEntries.map((e) =>
80	        e.blockerId === blockerId && e.blockedId === blockedId ? { ...e, status: "resolved" } : e,
81	      ),
82	    };
83	  }
84	
85	  // Resolve in blocks map
86	  const blocksEntries = deps.blocks[blockerId];
87	  let newBlocks = { ...deps.blocks };
88	  if (blocksEntries) {
89	    newBlocks = {
90	      ...deps.blocks,
91	      [blockerId]: blocksEntries.map((e) =>
92	        e.blockerId === blockerId && e.blockedId === blockedId ? { ...e, status: "resolved" } : e,
93	      ),
94	    };
95	  }
96	
97	  return { blockedBy: newBlockedBy, blocks: newBlocks };
98	}
