100	/**
101	 * Remove a blockage entry entirely from both maps.
102	 * Idempotent: if entry doesn't exist, no error.
103	 */
104	export function deleteBlockage(
105	  deps: DependenciesFile,
106	  blockedId: IssueId,
107	  blockerId: IssueId,
108	): DependenciesFile {
109	  // Remove from blockedBy map
110	  let newBlockedBy = { ...deps.blockedBy };
111	  const blockedByEntries = deps.blockedBy[blockedId];
112	  if (blockedByEntries) {
113	    const filtered = blockedByEntries.filter(
114	      (e) => !(e.blockerId === blockerId && e.blockedId === blockedId),
115	    );
116	    if (filtered.length === 0) {
117	      const { [blockedId]: _, ...rest } = newBlockedBy;
118	      newBlockedBy = rest;
119	    } else {
120	      newBlockedBy = { ...deps.blockedBy, [blockedId]: filtered };
121	    }
122	  }
123	
124	  // Remove from blocks map
125	  let newBlocks = { ...deps.blocks };
126	  const blocksEntries = deps.blocks[blockerId];
127	  if (blocksEntries) {
128	    const filtered = blocksEntries.filter(
129	      (e) => !(e.blockerId === blockerId && e.blockedId === blockedId),
130	    );
131	    if (filtered.length === 0) {
132	      const { [blockerId]: _, ...rest } = newBlocks;
133	      newBlocks = rest;
134	    } else {
135	      newBlocks = { ...deps.blocks, [blockerId]: filtered };
136	    }
137	  }
138	
139	  return { blockedBy: newBlockedBy, blocks: newBlocks };
140	}
