142	/**
143	 * Count active entries in blocks[issueId] — used for impact score.
144	 */
145	export function getImpactScore(deps: DependenciesFile, issueId: IssueId): number {
146	  const blocks = deps.blocks[issueId];
147	  if (!blocks) return 0;
148	  return blocks.filter((entry) => entry.status === "active").length;
149	}
