151	/**
152	 * Detect if adding blockedId→blockerId would create a cycle.
153	 * Walk blockedBy graph transitively from blockerId.
154	 * If blockedId is reached at any point → cycle detected.
155	 * Only considers entries with status === "active".
156	 */
157	export function detectCycle(
158	  deps: DependenciesFile,
159	  blockedId: IssueId,
160	  blockerId: IssueId,
161	): boolean {
162	  const visited = new Set<IssueId>();
163	  const queue: IssueId[] = [blockerId];
164	
165	  while (queue.length > 0) {
166	    const current = queue.shift()!;
167	
168	    if (current === blockedId) return true;
169	    if (visited.has(current)) continue;
170	    visited.add(current);
171	
172	    const blockedByCurrent = deps.blockedBy[current] ?? [];
173	    for (const entry of blockedByCurrent) {
174	      if (entry.status === "active") {
175	        queue.push(entry.blockerId);
176	      }
177	    }
178	  }
179	
180	  return false;
181	}
